Pregunta:
d = {'x': 10, 'y': 20}

valor = d['x']
print(valor)

for i in range(5):
    if i == 2:
        continue
    print(i, end='')

try:
    resultado = 10 / 0
except ZeroDivisionError:
    print('A')
finally:
    print('B')

def multiplicar(a, b=2):
    return a * b

print(multiplicar(5))

class Animal:
    def __init__(self, nombre):
        self.nombre = nombre

perro = Animal("Firulais")
print(perro.nombre)

def suma(*args):
    return sum(args)

print(suma(1, 2, 3, 4))

def mayusculas(func):
    def wrapper():
        return func().upper()
    return wrapper

@mayusculas
def saludar():
    return "hola"

print(saludar())

class A:
    def hablar(self): return "A"
class B(A):
    def hablar(self): return "B"
class C(A):
    def hablar(self): return "C"
class D(B, C):
    pass

# MRO (Method Resolution Order)
d = D()
print(d.hablar())

class Base:
    def __init__(self):
        print("Base")

class Derivada(Base):
    def __init__(self):
        super().__init__()
        print("Derivada")

d = Derivada()
